import mongoose, { Schema, Document } from 'mongoose';

export enum UserGender {
  Male = 'male',
  Female = 'female',
  Another = 'another',
}

export enum UserStatus {
  Active = 'active',
  InActive = 'inactive',
  Deleted = 'deleted',
}

export enum UserRole {
  Admin = 'admin',
  Staff = 'staff',
  Teacher = 'teacher',
  Student = 'student',
}

export interface IUser extends Document {
  username: string;
  first_name: string;
  last_name: string;
  email: string;
  phone: string;
  image?: string;
  bio?: string;
  gender: UserGender;
  dob?: Date;
  address: string;
  identity_card: string;
  status: UserStatus;
  // NOTE: 'role' is removed — use UserRoleModel (userroles collection) instead
  password: string;
  refresh_token?: string;
  existing_license_num?: string;
  existing_license_rank?: string;
  zalo_user_id?: string;
  fcm_token?: string;
  created_at: Date;
  updated_at: Date;
}

const UserSchema = new Schema<IUser>({
  username: { type: String, required: true, unique: true, lowercase: true, trim: true },
  first_name: { type: String, required: true },
  last_name: { type: String, required: true },
  email: { type: String, required: true, unique: true, lowercase: true, trim: true },
  phone: { type: String, required: true },
  image: { type: String },
  bio: { type: String },
  gender: { type: String, enum: Object.values(UserGender), default: UserGender.Male },
  dob: { type: Date },
  address: { type: String, required: true },
  identity_card: { 
    type: String, 
    required: true,
    validate: {
      validator: function(v: string) {
        return /^\d{12}$/.test(v);
      },
      message: (props: any) => `${props.value} không phải là số CCCD hợp lệ (phải có đúng 12 chữ số)!`
    }
  },
  status: { type: String, enum: Object.values(UserStatus), default: UserStatus.Active },
  password: { type: String, required: true },
  refresh_token: { type: String },
  existing_license_num: { type: String, default: null },
  existing_license_rank: { type: String, default: null },
  zalo_user_id: { type: String, default: null },
  fcm_token: { type: String, default: null }
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

UserSchema.index({ 
  first_name: 'text', 
  last_name: 'text', 
  phone: 'text', 
  identity_card: 'text' 
}, { 
  name: 'SearchIndex',
  weights: { first_name: 10, last_name: 5, phone: 5, identity_card: 3 }
});
UserSchema.index({ phone: 1 });
UserSchema.index({ identity_card: 1 });
UserSchema.index({ created_at: -1 });

export const UserModel = mongoose.models.Users || mongoose.model<IUser>('Users', UserSchema);

import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseFeeStage {
  name: string;
  amount: number;
}

export interface ICourse extends Document {
  license_category_id?: Types.ObjectId | null;
  code: string; // Mã nội bộ của trung tâm
  name: string; // Tên khóa học
  system_course_id?: number;
  system_course_code?: string; // Mã báo cáo lên Sở GTVT
  curriculum_id?: number;
  management_record_number?: string;
  description?: string;
  report_start_date?: Date;
  start_date?: Date;
  end_date?: Date;
  dat_date?: Date; // Ngày tập trung chạy DAT
  cabin_date?: Date; // Ngày học Cabin
  decision_to_sign?: string;
  duration?: number;
  status: 'draft' | 'ongoing' | 'completed' | 'canceled';
  course_fee?: number;
  max_students?: number;

  // Extension for Web Admin
  internal_note?: string;
  note?: string;
  course_type?: string;
  fee_stages?: ICourseFeeStage[];
  created_at: Date;
  updated_at: Date;
}

const CourseSchema = new Schema<ICourse>({
  license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
  code: { type: String, required: true, unique: true, index: true },
  name: { type: String, required: true },
  system_course_id: { type: Number },
  system_course_code: { type: String },
  curriculum_id: { type: Number },
  management_record_number: { type: String },
  description: { type: String },
  report_start_date: { type: Date },
  start_date: { type: Date },
  end_date: { type: Date },
  dat_date: { type: Date },
  cabin_date: { type: Date },
  decision_to_sign: { type: String },
  duration: { type: Number },
  status: { 
    type: String, 
    enum: ['draft', 'ongoing', 'completed', 'canceled'], 
    default: 'draft' 
  },
  course_fee: { type: Number, default: 0 },
  max_students: { type: Number, default: 50 },
  internal_note: { type: String },
  note: { type: String },
  course_type: { type: String, default: 'trực tiếp' },
  fee_stages: [{
    name: { type: String },
    amount: { type: Number, default: 0 }
  }],
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false,
  collection: 'courses'
});

CourseSchema.index({ status: 1 });
CourseSchema.index({ start_date: -1 });

if (mongoose.models.Courses) {
  mongoose.deleteModel('Courses');
}
export const CourseModel = mongoose.model<ICourse>('Courses', CourseSchema, 'courses');

import mongoose, { Schema, Document, Types } from 'mongoose';

export interface ICourseStudent extends Document {
  student_id: Types.ObjectId; // References Student(student_infos)
  course_id: Types.ObjectId; // References Course(course_infos)
  stadium_id?: Types.ObjectId | null;
  teacher_id?: Types.ObjectId | null;
  sale_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  status: 'unfinished' | 'finished' | 'canceled';
  km: number;
  hour: string;
  fee: number;
  paid_fee: number;
  balance?: any; // Treasury balance for this enrollment
  contract_date?: Date | null;
  status_detail?: string;
  progress_flags?: {
    theory_completed: boolean;
    sand_yard_completed: boolean;
    simulation_completed: boolean;
    dat_completed: boolean;
    cabin_completed: boolean;
    graduation_eligible: boolean;
  };
  health_check?: {
    status: string;
    date: Date | null;
    hospital: string | null;
    note: string | null;
  };
  created_at: Date;
  updated_at: Date;
}

const CourseStudentSchema = new Schema<ICourseStudent>({
  student_id: { type: Schema.Types.ObjectId, ref: 'StudentInfos', required: true, index: true },
  course_id: { type: Schema.Types.ObjectId, ref: 'Courses', required: true, index: true },
  stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums', default: null },
  teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
  sale_id: { type: Schema.Types.ObjectId, ref: 'Users', default: null },
  license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },
  status: { 
    type: String, 
    enum: ['unfinished', 'finished', 'canceled'], 
    default: 'unfinished' 
  },
  km: { type: Number, default: 0 },
  hour: { type: String, default: '00:00' },
  fee: { type: Number, default: 0 },
  paid_fee: { type: Number, default: 0 },
  balance: { 
    type: Schema.Types.Decimal128, 
    default: 0,
    get: (v: any) => (v ? parseFloat(v.toString()) : 0)
  },
  contract_date: { type: Date, default: null },
  status_detail: { type: String, default: 'Chờ KSK' },
  progress_flags: {
    theory_completed: { type: Boolean, default: false },
    sand_yard_completed: { type: Boolean, default: false },
    simulation_completed: { type: Boolean, default: false },
    dat_completed: { type: Boolean, default: false },
    cabin_completed: { type: Boolean, default: false },
    graduation_eligible: { type: Boolean, default: false },
  },
  health_check: {
    status: { type: String, enum: ['Chờ khám', 'Đủ điều kiện', 'Không đủ điều kiện'], default: 'Chờ khám' },
    date: { type: Date, default: null },
    hospital: { type: String, default: null },
    note: { type: String, default: null },
  },
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false,
  collection: 'coursestudents'
});

CourseStudentSchema.index({ student_id: 1, created_at: -1 });
CourseStudentSchema.index({ course_id: 1, created_at: -1 });
CourseStudentSchema.index({ status_detail: 1, created_at: -1 });
CourseStudentSchema.index({ sale_id: 1, created_at: -1 });
CourseStudentSchema.index({ 'progress_flags.dat_completed': 1, status_detail: 1 });
CourseStudentSchema.index({ fee: 1, paid_fee: 1 });

export const CourseStudentModel = mongoose.models.CourseStudents || mongoose.model<ICourseStudent>('CourseStudents', CourseStudentSchema, 'coursestudents');

import mongoose, { Schema, Document, Types } from 'mongoose';

export enum PaymentType {
  TuitionFee = 'tuition_fee',
  ChipRegistrationFee = 'chip_registration_fee',
  PickupFee = 'pickup_fee',
  ChipDepositFee = 'chip_deposit_fee',
  ReExamFee = 're_exam_fee',
  TheoryCompleted = 'theory_completed',
  PracticeCompleted = 'practice_completed',
  GraduationExam = 'graduation_exam',
  Other = 'other',
}

export interface IPayment extends Document {
  course_student_id: Types.ObjectId;
  sale_id?: Types.ObjectId;
  payment_date: Date;
  type: PaymentType;
  note?: string;
  confirmer_id?: Types.ObjectId; // User ID who confirmed the payment
  is_received: boolean;
  received_fee: number;
  stage_name?: string; // Tên đợt đóng phí tùy chỉnh từ settings
  created_at: Date;
  updated_at: Date;
  is_deleted: boolean;
  deleted_at: Date | null;
}

const PaymentSchema = new Schema<IPayment>({
  course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', required: true, index: true },
  sale_id: { type: Schema.Types.ObjectId, ref: 'Users' },
  payment_date: { type: Date, required: true },
  type: { 
    type: String, 
    enum: Object.values(PaymentType), 
    required: true 
  },
  note: { type: String },
  confirmer_id: { type: Schema.Types.ObjectId, ref: 'Users' },
  is_received: { type: Boolean, default: false },
  received_fee: { type: Number, default: 0 },
  stage_name: { type: String },
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

PaymentSchema.index({ payment_date: -1 });
PaymentSchema.index({ type: 1 });

export const PaymentModel = mongoose.models.Payments || mongoose.model<IPayment>('Payments', PaymentSchema);

import mongoose, { Schema, Document, Types } from 'mongoose';
import { IUser } from './user.model';

export interface IStudent extends Document {
  user_id: Types.ObjectId | IUser; // Can be ID or populated User object
  card_id?: string | null;
  profile_created_at?: Date | null;
  email_verified_at?: Date | null;
  lead_id?: Types.ObjectId | null;
  region_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  course_id?: Types.ObjectId | null;
  balance?: any;
  created_at: Date;
  updated_at: Date;
  is_deleted: boolean;
  deleted_at: Date | null;
  // Merged fields from Enrollment for UI/Tests (Source of truth is CourseStudent)
  status_detail?: string;
}

const StudentSchema = new Schema<IStudent>({
  user_id: { type: Schema.Types.ObjectId, ref: 'Users', required: true, index: true },
  balance: { 
    type: Schema.Types.Decimal128, 
    default: 0,
    get: (v: any) => (v ? parseFloat(v.toString()) : 0)
  },
  card_id: { type: String, default: null },
  profile_created_at: { type: Date, default: null },
  email_verified_at: { type: Date, default: null },
  lead_id: { type: Schema.Types.ObjectId, ref: 'Lead_Infos', default: null },
  course_id: { type: Schema.Types.ObjectId, ref: 'Courses', default: null },
  license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories', default: null },

  // Extension
  region_id: { type: Schema.Types.ObjectId, ref: 'Cities', default: null },
  is_deleted: { type: Boolean, default: false, index: true },
  deleted_at: { type: Date, default: null },

  // Merged fields for UI/Tests (Primary source is CourseStudent)
  status_detail: { type: String, default: 'Chờ KSK' },
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false,
  collection: 'studentinfos'
});

StudentSchema.index({ region_id: 1, created_at: -1 });
StudentSchema.index({ created_at: -1, is_deleted: 1 });
StudentSchema.index({ course_id: 1, created_at: -1 });
StudentSchema.index({ license_category_id: 1, created_at: -1 });

if (mongoose.models.StudentInfos) {
  mongoose.deleteModel('StudentInfos');
}
export const StudentModel = mongoose.model<IStudent>('StudentInfos', StudentSchema, 'studentinfos');

import mongoose, { Schema, Document, Types } from 'mongoose';

export enum LessonStatus {
  Pending = 'pending',
  InProgress = 'in_progress',
  Completed = 'completed',
  NoTeacher = 'no_teacher',
  CanceledClass = 'canceled_class',
  DroppedClass = 'dropped_class',
  Deleted = 'deleted',
}

export enum LessonCategory {
  Theory = 'theory',
  Practice = 'practice',
}

export interface ILesson extends Document {
  course_student_id?: Types.ObjectId;
  student_id?: Types.ObjectId; // References User(student)
  teacher_id?: Types.ObjectId; // References User(teacher)
  name: string;
  category: LessonCategory;
  status: LessonStatus;
  start_time: Date;
  end_time: Date;
  description?: string;
  lesson_type_id?: Types.ObjectId;
  vehicle_id?: Types.ObjectId;
  is_night_course: boolean;
  is_automatic_course: boolean;
  km: number;
  hour: string;
  vehicle_type?: string;
  stadium_id?: Types.ObjectId;
  order: number;
  confirmed: boolean;
  pickup_point?: string;
  is_pickup: boolean;
  created_at: Date;
  updated_at: Date;
}

const LessonSchema = new Schema<ILesson>({
  course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', index: true },
  student_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
  teacher_id: { type: Schema.Types.ObjectId, ref: 'Users', index: true },
  name: { type: String, required: true },
  category: { 
    type: String, 
    enum: Object.values(LessonCategory), 
    default: LessonCategory.Practice,
    required: true 
  },
  status: { 
    type: String, 
    enum: Object.values(LessonStatus), 
    default: LessonStatus.Pending,
    required: true 
  },
  start_time: { type: Date, required: true, index: true },
  end_time: { type: Date, required: true },
  description: { type: String, default: '' },
  lesson_type_id: { type: Schema.Types.ObjectId },
  vehicle_id: { type: Schema.Types.ObjectId },
  is_night_course: { type: Boolean, default: false },
  is_automatic_course: { type: Boolean, default: false },
  km: { type: Number, default: 0 },
  hour: { type: String, default: '00:00' },
  vehicle_type: { type: String, enum: ['car', 'motorbike'] },
  stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums' },
  order: { type: Number, default: 1 },
  confirmed: { type: Boolean, default: false },
  pickup_point: { type: String },
  is_pickup: { type: Boolean, default: false },
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

export const LessonModel = mongoose.models.Lessons || mongoose.model<ILesson>('Lessons', LessonSchema);

import type {} from "../types/express.d";
import { Request, Response } from "express";
import mongoose from "mongoose";
import { StudentModel } from "@/infrastructure/database/models/student.model";
import { CourseStudentModel } from "@/infrastructure/database/models/course_student.model";
import { NotificationModel } from "@/infrastructure/database/models/notification.model";
import { ExamScheduleModel } from "@/infrastructure/database/models/exam_schedule.model";
import { catchAsync } from "@/interface/middlewares/catchAsync.middleware";
import { ctrlLogger } from "@/infrastructure/logging/controller-logger";
import { ExcelHelper } from "@/infrastructure/utils/excel.helper";
import { NotifyService } from "@/application/services/notify.service";

const notifyService = new NotifyService();

export const getDashboardStats = catchAsync(
  async (req: Request, res: Response) => {
    const log = ctrlLogger("dashboard.get_stats", req);
    log.start({ userId: (req.user as any)?.id ?? (req.user as any)?._id });
    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // --- MONTH BOUNDARIES ---
    const startOfThisMonth = new Date(today.getFullYear(), today.getMonth(), 1);
    const startOfLastMonth = new Date(
      today.getFullYear(),
      today.getMonth() - 1,
      1,
    );
    const endOfLastMonth = new Date(
      today.getFullYear(),
      today.getMonth(),
      0,
      23,
      59,
      59,
      999,
    );

    const sevenDaysLater = new Date(today);
    sevenDaysLater.setDate(today.getDate() + 7);
    sevenDaysLater.setHours(23, 59, 59, 999);

    const thirtyDaysLater = new Date(today);
    thirtyDaysLater.setDate(today.getDate() + 30);
    thirtyDaysLater.setHours(23, 59, 59, 999);

    const fortyEightHoursLater = new Date();
    fortyEightHoursLater.setHours(fortyEightHoursLater.getHours() + 48);

    // --- DATA ISOLATION ---
    const studentMatch: any = { is_deleted: false };
    const enrollmentMatch: any = {};
    const userId = (req.user as any)?.id || (req.user as any)?._id;

    if (req.user?.role === "teacher") {
      const assignedStudentIds = await CourseStudentModel.find({
        teacher_id: userId,
      })
        .distinct("student_id")
        .exec();
      studentMatch._id = { $in: assignedStudentIds };
      enrollmentMatch.teacher_id = new mongoose.Types.ObjectId(userId);
    }

    // 1. Core counts (Filtered by teacher if necessary)
    const [totalStudents, thisMonthCount, lastMonthCount] = await Promise.all([
      StudentModel.countDocuments(studentMatch),
      StudentModel.countDocuments({
        ...studentMatch,
        created_at: { $gte: startOfThisMonth },
      }),
      StudentModel.countDocuments({
        ...studentMatch,
        created_at: { $gte: startOfLastMonth, $lte: endOfLastMonth },
      }),
    ]);

    // 2. Monthly growth %
    const monthlyGrowthPercent =
      lastMonthCount > 0
        ? Math.round(((thisMonthCount - lastMonthCount) / lastMonthCount) * 100)
        : thisMonthCount > 0
          ? 100
          : 0;

    // 3. Status distribution (Aggregating from StudentModel for consistency with list)
    const statusCounts = await StudentModel.aggregate([
      { $match: studentMatch },
      {
        $group: {
          _id: { $ifNull: ["$status_detail", "Chờ KSK"] },
          count: { $sum: 1 },
        },
      },
    ]);

    // 4. Total tuition debt
    const debtAgg = await CourseStudentModel.aggregate([
      { $match: { ...enrollmentMatch, $expr: { $lt: ["$paid_fee", "$fee"] } } },
      {
        $group: {
          _id: null,
          totalDebt: { $sum: { $subtract: ["$fee", "$paid_fee"] } },
          count: { $sum: 1 },
        },
      },
    ]);
    const totalDebtAmount = debtAgg[0]?.totalDebt ?? 0;
    const tuitionDebtCount = debtAgg[0]?.count ?? 0;

    // 5. Weekly exam count
    const weeklyExamCount = await ExamScheduleModel.countDocuments({
      start_time: { $gte: today, $lte: sevenDaysLater },
    });

    // 6. Upcoming exams (30 days) - Robust query and formatting
    const rawUpcoming = await ExamScheduleModel.find({
      start_time: { $gte: today, $lte: thirtyDaysLater },
    })
      .sort({ start_time: 1 })
      .limit(5)
      .populate({
        path: "exam_id",
        select: "name exam_type license_category_id",
        populate: { path: "license_category_id", select: "name" },
      })
      .lean();

    const upcomingExams = rawUpcoming.map((e: any) => {
      const exam = e.exam_id as any;
      // Handle cases where exam_id might be a dangling reference (deleted exam)
      return {
        ...e,
        exam_id: {
          _id: exam?._id || e.exam_id || "deleted",
          name: exam?.name || "Kỳ thi không tên (Đã xóa)",
          exam_type: exam?.exam_type || "sat_hach",
          license_category_id: exam?.license_category_id?.name || "B2",
        },
      };
    });

    // 7. Latest registrations (Student Profiles)
    const rawLatest = await StudentModel.find(studentMatch)
      .sort({ created_at: -1 })
      .limit(5)
      .populate("user_id", "first_name last_name phone email identity_card")
      .populate("license_category_id", "name")
      .populate("region_id", "name")
      .lean();

    const latestRegistrations = await Promise.all(
      rawLatest.map(async (st: any) => {
        const user = st.user_id as any;
        const region = st.region_id as any;

        // Check if truly enrolled (existence in CourseStudent) if fields are missing on profile
        let courseId = st.course_id;
        let rankId = st.license_category_id as any;

        if (!courseId || !rankId) {
          const enrollment = await CourseStudentModel.findOne({
            student_id: st._id,
          })
            .populate("license_category_id", "name")
            .lean();

          if (enrollment) {
            if (!courseId) courseId = enrollment.course_id;
            if (!rankId) rankId = enrollment.license_category_id;
          }
        }

        return {
          ...st,
          id: st._id.toString(),
          user_id: user,
          region_id: region,
          status_detail: st.status_detail || "Chờ KSK",
          license_category_id:
            rankId?.name ||
            (st.license_category_id as any)?.name ||
            "Chưa phân hạng",
          course_id: courseId || null,
          region: region ? region.name : "Chưa xác định",
        };
      }),
    );

    // 8. Region distribution (from StudentModel for global reach analysis)
    const regionStats = await StudentModel.aggregate([
      { $match: studentMatch },
      {
        $lookup: {
          from: "cities",
          localField: "region_id",
          foreignField: "_id",
          as: "region",
        },
      },
      { $unwind: { path: "$region", preserveNullAndEmptyArrays: true } },
      {
        $group: {
          _id: { $ifNull: ["$region.name", "Chưa xác định"] },
          count: { $sum: 1 },
        },
      },
      { $sort: { count: -1 } },
    ]);

    // 9. Recruiter (Sale) distribution
    const recruiterStats = await CourseStudentModel.aggregate([
      { $match: enrollmentMatch },
      {
        $lookup: {
          from: "users",
          localField: "sale_id",
          foreignField: "_id",
          as: "recruiter",
        },
      },
      { $unwind: { path: "$recruiter", preserveNullAndEmptyArrays: true } },
      {
        $group: {
          _id: {
            $cond: [
              { $not: ["$sale_id"] },
              "Chưa gán",
              {
                $ifNull: [
                  {
                    $concat: [
                      "$recruiter.last_name",
                      " ",
                      "$recruiter.first_name",
                    ],
                  },
                  "Chưa gán",
                ],
              },
            ],
          },
          count: { $sum: 1 },
        },
      },
      { $sort: { count: -1 } },
    ]);

    // 10. === URGENT TASKS GENERATOR ===
    const urgentTasks: Array<{
      type: "debt" | "exam" | "dat";
      title: string;
      subTitle: string;
      value?: string;
      badge?: string;
    }> = [];

    // Top debt enrollments
    const debtStudents = await CourseStudentModel.find({
      ...enrollmentMatch,
      $expr: { $lt: ["$paid_fee", "$fee"] },
    })
      .sort({ paid_fee: 1 })
      .limit(2)
      .populate({
        path: "student_id",
        populate: { path: "user_id", select: "first_name last_name" },
      });

    for (const cs of debtStudents) {
      const st = cs.student_id as any;
      const u = st?.user_id;
      const debtAmount = (cs.fee ?? 0) - (cs.paid_fee ?? 0);
      urgentTasks.push({
        type: "debt",
        title: u ? `${u.last_name} ${u.first_name}` : "Học viên ẩn",
        subTitle: "Hạn đóng học phí chưa thanh toán",
        value: `-${debtAmount.toLocaleString("vi-VN")} đ`,
      });
    }

    // Exams within 48h
    const urgentExams = await ExamScheduleModel.find({
      start_time: { $gte: new Date(), $lte: fortyEightHoursLater },
    })
      .sort({ start_time: 1 })
      .limit(2)
      .populate({
        path: "exam_id",
        select: "name license_category_id",
        populate: { path: "license_category_id", select: "name" },
      });

    for (const e of urgentExams) {
      const exam = e.exam_id as { name: string; license_category_id: string };
      const startDate = new Date(e.start_time);
      const dayLabel = startDate.toLocaleDateString("vi-VN", {
        weekday: "long",
        hour: "2-digit",
        minute: "2-digit",
      });
      urgentTasks.push({
        type: "exam",
        title: exam?.name ?? "Kỳ thi sắp diễn ra",
        subTitle: `Khai mạc: ${dayLabel}`,
        badge: (exam?.license_category_id as any)?.name ?? "B2",
      });
    }

    // Enrollments with incomplete DAT
    const datPendingStudents = await CourseStudentModel.find({
      ...enrollmentMatch,
      "progress_flags.dat_completed": false,
      status_detail: { $in: ["Đang học", "Chờ thi"] },
    })
      .limit(2)
      .populate({
        path: "student_id",
        populate: { path: "user_id", select: "first_name last_name" },
      })
      .populate({
        path: "course_id",
        populate: { path: "license_category_id", select: "name" },
      });

    for (const cs of datPendingStudents) {
      const st = cs.student_id as any;
      const u = st?.user_id;
      const course = cs.course_id as any;
      urgentTasks.push({
        type: "dat",
        title: u ? `${u.last_name} ${u.first_name}` : "Học viên ẩn",
        subTitle: "Chưa hoàn thành số giờ lái DAT",
        badge: course?.license_category_id?.name ?? "B2",
      });
    }

    // --- Format status counts ---
    const countsMap: Record<string, number> = {
      total: totalStudents,
      tuitionDebt: tuitionDebtCount,
    };
    statusCounts.forEach((item: any) => {
      if (item._id) {
        let label = item._id;
        // Normalize legacy labels
        if (label === "Đã xong KSK") label = "Đã KSK";

        countsMap[label] = (countsMap[label] || 0) + item.count;
      }
    });

    // 11. Unread notification count & recent (Using new NotifyService)
    const unreadNotificationCount = await notifyService.getUnreadCount(userId);
    const recentRes = await notifyService.getByUser(userId, { page: 1, limit: 5 });
    const recentNotifications = recentRes.data;

    log.success(
      res,
      {
        counts: countsMap,
        totalDebtAmount,
        monthlyGrowthPercent,
        thisMonthCount,
        weeklyExamCount,
        urgentTasks,
        unreadNotificationCount,
        recentNotifications,
        latestRegistrations,
        upcomingExams,
        regionStats,
        recruiterStats,
      },
      "Dashboard statistics retrieved successfully",
    );
  },
);

