import { ExamBatchRepository } from '@/infrastructure/database/repositories/exam_batch.repository';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';
import * as fs from 'fs';

const examBatchRepository = new ExamBatchRepository();
const examBatchService = new ExamBatchService(examBatchRepository);

export const createBatch = catchAsync(async (req: Request, res: Response) => {
  const batch = await examBatchService.createBatch(req.body);
  res.statusSuccess(batch, 'Exam batch created successfully');
});

export const getAllBatches = catchAsync(async (req: Request, res: Response) => {
  const batches = await examBatchService.getAllBatches(req.pagination);
  res.statusSuccess(batches, 'Exam batches retrieved successfully');
});

export const getBatchById = catchAsync(async (req: Request, res: Response) => {
  const batch = await examBatchService.getBatchById((typeof req.params.id === 'string' ? req.params.id : req.params.id[0]));
  if (!batch) {
    return res.statusError('Exam batch not found', 404);
  }
  res.statusSuccess(batch, 'Exam batch retrieved successfully');
});

export const updateBatch = catchAsync(async (req: Request, res: Response) => {
  const batch = await examBatchService.updateBatch((typeof req.params.id === 'string' ? req.params.id : req.params.id[0]), req.body);
  if (!batch) {
    return res.statusError('Exam batch not found', 404);
  }
  res.statusSuccess(batch, 'Exam batch updated successfully');
});

export const deleteBatch = catchAsync(async (req: Request, res: Response) => {
  const idStr = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  await examBatchService.deleteBatch(idStr);
  res.statusSuccess(null, 'Exam batch deleted successfully');
});

export const exportBatches = catchAsync(async (req: Request, res: Response) => {
  await examBatchService.exportBatchesToExcel(res, req.query);
});

export const getStats = catchAsync(async (req: Request, res: Response) => {
  const stats = await examBatchService.getStats();
  res.statusSuccess(stats, 'Exam batch statistics retrieved successfully');
});

export const getBatchStats = catchAsync(async (req: Request, res: Response) => {
  const idStr = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  const stats = await examBatchService.getBatchStats(idStr);
  if (!stats) return res.statusError('Batch not found', 404);
  res.statusSuccess(stats, 'Batch stats retrieved successfully');
});

export const importResults = catchAsync(async (req: Request, res: Response) => {
  if (!req.file) {
    return res.statusError('No file uploaded', 400);
  }

  const batchId = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  const results = await examBatchService.importResults(batchId, req.file.path);

  // Clean up uploaded file
  if (fs.existsSync(req.file.path)) {
    fs.unlinkSync(req.file.path);
  }

  res.statusSuccess(results, 'Exam results imported successfully');
});

export const getImportTemplate = catchAsync(async (req: Request, res: Response) => {
  await examBatchService.getTemplate(res);
});

import { Request, Response } from 'express';
import { StadiumService } from '@/application/services/stadium.service';
import { catchAsync } from '@/interface/middlewares/catchAsync.middleware';

export class StadiumController {
  private stadiumService: StadiumService;

  constructor() {
    this.stadiumService = new StadiumService();
    this.getAll = this.getAll.bind(this);
    this.getById = this.getById.bind(this);
    this.create = this.create.bind(this);
    this.update = this.update.bind(this);
    this.delete = this.delete.bind(this);
  }

  getAll = catchAsync(async (req: Request, res: Response) => {
    const { page, limit, city, search, region_id } = req.query;
    const result = await this.stadiumService.getAllStadiums(
      { 
        city: city as string, 
        region_id: region_id as string,
        search: search as string 
      },
      { page: Number(page) || 1, limit: Number(limit) || 10 }
    );
    (res as any).statusSuccess({
      items: result.docs,
      pagination: {
        total: result.total,
        page: result.page,
        limit: result.limit,
        totalPages: result.totalPages
      }
    }, 'Stadiums retrieved successfully');
  });

  getById = catchAsync(async (req: Request, res: Response) => {
    const stadium = await this.stadiumService.getStadiumById(req.params.id as string);
    if (!stadium) {
      return res.status(404).json({ success: false, message: 'Stadium not found' });
    }
    res.json({ success: true, data: stadium });
  });

  create = catchAsync(async (req: Request, res: Response) => {
    const stadium = await this.stadiumService.createStadium(req.body);
    (res as any).statusSuccess(stadium, 'Stadium created successfully', 201);
  });

  update = catchAsync(async (req: Request, res: Response) => {
    const stadium = await this.stadiumService.updateStadium(req.params.id as string, req.body);
    if (!stadium) {
      return (res as any).statusError('Stadium not found', 404);
    }
    (res as any).statusSuccess(stadium, 'Stadium updated successfully');
  });

  delete = catchAsync(async (req: Request, res: Response) => {
    const stadium = await this.stadiumService.deleteStadium(req.params.id as string);
    if (!stadium) {
      return (res as any).statusError('Stadium not found', 404);
    }
    (res as any).statusSuccess(null, 'Stadium deleted successfully');
  });
}

