import { Request, Response, NextFunction } from 'express';

export const rbacMiddleware = (allowedRoles: string[]) => {
  return (req: Request, res: Response, next: NextFunction) => {
    // 1. Lấy user từ request (đã được Auth middleware populate)
    const user = (req as any).user;

    if (!user) {
      return res.status(401).json({
        success: false,
        message: 'Unauthorized: No user found'
      });
    }

    // 2. Kiểm tra vai trò
    const hasRole = allowedRoles.includes(user.role);

    if (!hasRole) {
      return res.status(403).json({
        success: false,
        message: `Forbidden: Requires one of [${allowedRoles.join(', ')}] roles`
      });
    }

    next();
  };
};

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import logger from '@/infrastructure/logging/logger';
import { tokenBlacklist } from '@/infrastructure/security/token-blacklist.service';

export interface AuthRequest extends Request {
  user?: any;
}

export const authenticateJWT = (req: AuthRequest, res: Response, next: NextFunction) => {
  const authHeader = req.headers.authorization;

  if (authHeader) {
    const token = authHeader.split(' ')[1]; // Bearer <token>

    if (tokenBlacklist.has(token)) {
      return res.status(401).json({
        success: false,
        message: 'Unauthorized: Token has been revoked'
      });
    }

    const secret = process.env.JWT_SECRET!;

    jwt.verify(token, secret, (err, user) => {
      if (err) {
        logger.error(`JWT Verification Error: ${err.message}`);
        return res.status(403).json({
          success: false,
          message: 'Access denied: Invalid or expired token'
        });
      }

      req.user = user;
      next();
    });
  } else {
    return res.status(401).json({
      success: false,
      message: 'Unauthorized: No token provided'
    });
  }
};

import mongoose, { Schema, Document, Types } from 'mongoose';

export enum ExamType {
  Graduation = 'graduation',
  SatHach = 'sat_hach',
}

export enum ExamResult {
  Pass = 'pass',
  Fail = 'fail',
  NoResult = 'no_result',
}

export interface IExamTypeResult {
  result: string;
  name: string;
  lesson_type_id?: string;
  description?: string;
}

export interface IExam extends Document {
  course_student_id?: Types.ObjectId | null;
  exam_types?: Map<string, IExamTypeResult>;
  stadium_id?: Types.ObjectId | null;
  license_category_id?: Types.ObjectId | null;
  parent_id?: Types.ObjectId | null;

  name: string;
  status: string;
  exam_type: ExamType;

  start_time?: Date;
  end_time?: Date;

  description?: string;
  session?: string;
  exam_number?: number;

  is_pickup: boolean;
  pickup_point?: string;
  location?: string;
  result: ExamResult;
  registration_number?: string;
  studentResults?: any[];

  created_at: Date;
  updated_at: Date;
}

const IExamTypeResultSchema = new Schema({
  result: { type: String },
  name: { type: String },
  lesson_type_id: { type: String },
  description: { type: String },
}, { _id: false });

const ExamSchema = new Schema<IExam>({
  course_student_id: { type: Schema.Types.ObjectId, ref: 'CourseStudents', index: true },
  exam_types: {
    type: Map,
    of: IExamTypeResultSchema,
  },
  stadium_id: { type: Schema.Types.ObjectId, ref: 'Stadiums' },
  license_category_id: { type: Schema.Types.ObjectId, ref: 'LicenseCategories' },
  parent_id: { type: Schema.Types.ObjectId, ref: 'Exams', default: null },

  name: { type: String, required: true, trim: true },
  status: { type: String, trim: true },
  exam_type: { type: String, enum: Object.values(ExamType), required: true },

  start_time: { type: Date, index: true },
  end_time: { type: Date },

  description: { type: String, default: '' },
  session: { type: String },
  exam_number: { type: Number },

  is_pickup: { type: Boolean, default: false },
  pickup_point: { type: String },
  location: { type: String },
  result: { type: String, enum: Object.values(ExamResult), default: ExamResult.NoResult },
  registration_number: { type: String },
  studentResults: [{ type: Schema.Types.Mixed }],
}, {
  timestamps: { createdAt: 'created_at', updatedAt: 'updated_at' },
  versionKey: false
});

ExamSchema.index({ exam_type: 1 });
ExamSchema.index({ stadium_id: 1 });

export const ExamModel = mongoose.models.Exams || mongoose.model<IExam>('Exams', ExamSchema);

