      { header: 'Số điện thoại', key: 'phone', width: 15 },
      { header: 'Khóa học', key: 'course', width: 20 },
      { header: 'Hạng', key: 'rank', width: 10 },
      { header: 'Số tiền thu', key: 'amount', width: 18 },
      { header: 'Giai đoạn', key: 'stage', width: 18 },
      { header: 'Ngày thu', key: 'date', width: 15 },
      { header: 'Đã nhận tiền', key: 'is_received', width: 15 },
      { header: 'Ghi chú', key: 'note', width: 30 },
    ]);

    data.forEach((p: any) => {
      // Repository populates: course_student_id → { student_id: { user_id: {...} }, course_id: {...} }
      const courseStudent = p.course_student_id || {};
      const studentDoc   = courseStudent.student_id  || {};
      const userDoc      = studentDoc.user_id        || {};
