        date: p.payment_date
          ? new Date(p.payment_date).toLocaleDateString('vi-VN')
          : p.created_at ? new Date(p.created_at).toLocaleDateString('vi-VN') : '',
        is_received: p.is_received ? 'Đã nhận' : 'Chưa nhận',
