    // Double-header or "Logo" area
    const logoRow = summarySheet.insertRow(1, ['BÁO CÁO TÀI CHÍNH TỔNG HỢP - HỆ THỐNG AHV', '']);
    summarySheet.mergeCells('A1:B1');
    logoRow.height = 50;
    logoRow.getCell(1).font = { bold: true, size: 20, color: { argb: 'FFFFFFFF' } };
    logoRow.getCell(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF4F46E5' } };
    logoRow.getCell(1).alignment = { vertical: 'middle', horizontal: 'center' };

    summarySheet.addRows([
      { label: '👉 Tổng doanh thu dự kiến (Định mức học phí)', value: Number(stats.total_receivable || 0) },
      { label: '💰 Tổng số tiền đã thực thu (Tiền mặt/Chuyển khoản)', value: Number(stats.total_received || 0) },
      { label: '📉 Tổng công nợ còn lại (Cần thu hồi)', value: Number(stats.total_debt || 0) },
      { label: '👥 Số lượng học viên còn nợ', value: Number(stats.debtor_count || 0) },
      { label: '📈 Tỷ lệ hoàn thành thu nợ', value: (stats.total_receivable > 0 ? (stats.total_received / stats.total_receivable * 100).toFixed(2) + '%' : '0%') },
