## 4. Thiết Kế Data Isolation Helper

### 4.1 Tạo DataIsolationHelper Service

```typescript
// src/application/services/data-isolation.helper.ts

import mongoose from 'mongoose';
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { UserRole } from '@/infrastructure/database/models/user.model';

export interface AuthUser {
  id: string;
  _id: mongoose.Types.ObjectId;
  role: UserRole;
}

export class DataIsolationHelper {

  /**
   * Lấy danh sách student_ids mà teacher được phân công
   */
  static async getAssignedStudentIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('student_id');

    return courseStudents;
  }

  /**
   * Lấy danh sách course_ids mà teacher được phân công
   */
  static async getAssignedCourseIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('course_id');

    return courseStudents;
  }

  /**
   * Lấy danh sách course_student_ids mà teacher được phân công
   */
  static async getAssignedCourseStudentIds(teacherId: string | mongoose.Types.ObjectId): Promise<mongoose.Types.ObjectId[]> {
    const courseStudents = await CourseStudentModel.find({
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    }).distinct('_id');

    return courseStudents;
  }

  /**
   * Kiểm tra xem student có thuộc quyền quản lý của teacher không
   */
  static async isStudentAssignedToTeacher(
    studentId: string | mongoose.Types.ObjectId,
    teacherId: string | mongoose.Types.ObjectId
  ): Promise<boolean> {
    const count = await CourseStudentModel.countDocuments({
      student_id: studentId,
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    });
    return count > 0;
  }

  /**
   * Kiểm tra xem course có thuộc quyền quản lý của teacher không
   */
  static async isCourseAssignedToTeacher(
    courseId: string | mongoose.Types.ObjectId,
    teacherId: string | mongoose.Types.ObjectId
  ): Promise<boolean> {
    const count = await CourseStudentModel.countDocuments({
      course_id: courseId,
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    });
    return count > 0;
  }

  /**
   * Build filter cho teacher - trả về query filter
   */
  static buildTeacherFilter(teacherId: string | mongoose.Types.ObjectId): any {
    return {
      teacher_id: teacherId,
      status: { $ne: 'canceled' }
    };
  }

  /**
   * Build course_student filter cho payment/exam queries
   */
  static async buildCourseStudentFilter(teacherId: string | mongoose.Types.ObjectId): Promise<any> {
    const courseStudentIds = await this.getAssignedCourseStudentIds(teacherId);
    return {
      course_student_id: { $in: courseStudentIds }
    };
  }

  /**
   * Apply data isolation based on user role
   * Returns the appropriate filter for queries
   */
  static async applyDataIsolation(user: AuthUser): Promise<{
    filter: any;
    lookupFields: string[];
    skipAccessCheck: boolean;
  }> {
    switch (user.role) {
      case UserRole.Admin:
      case UserRole.Staff:
        return {
          filter: {},
          lookupFields: [],
          skipAccessCheck: true
        };

      case UserRole.Teacher:
        const courseStudentIds = await this.getAssignedCourseStudentIds(user.id);
        return {
          filter: { course_student_id: { $in: courseStudentIds } },
          lookupFields: ['course_student_id'],
          skipAccessCheck: false
        };

      case UserRole.Student:
        return {
          filter: { user_id: user.id },
          lookupFields: [],
          skipAccessCheck: false
        };

      default:
        return {
          filter: { _id: null }, // Deny all
          lookupFields: [],
          skipAccessCheck: false
        };
    }
  }
}
```

