### Phase 1: Core Infrastructure (High Priority)

#### 1.1 Update Course Controller

```typescript
// src/interface/controllers/course.controller.ts

export const getAllCourses = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('course.get_all', req);
  log.start({ query: req.query });

  const filters = { ...req.query };

  // === DATA ISOLATION ===
  if (req.user?.role === 'teacher') {
    const teacherId = req.user.id;
    // Teacher chỉ thấy courses mà có học viên được gán cho họ
    const assignedCourseIds = await DataIsolationHelper.getAssignedCourseIds(teacherId);

    // Nếu có thêm filter course_id từ query
    if (filters._id || filters.id) {
      const requestedCourseId = filters._id || filters.id;
      const isAuthorized = assignedCourseIds.some(
        id => id.toString() === requestedCourseId.toString()
      );
      if (!isAuthorized) {
        return log.fail('access_denied', res, 403, 'Bạn không có quyền truy cập khóa học này');
      }
    } else {
      // Filter chỉ hiển thị courses được gán
      filters.course_ids = { $in: assignedCourseIds };
    }
  }
  // Admin/Staff: không filter

  const courses = await courseService.getAllCourses(filters, req.pagination);
  log.success(res, courses, 'Courses retrieved successfully');
});

export const getCourseById = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('course.get_by_id', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  log.start({ courseId: idStr });

  // === DATA ISOLATION ===
  if (req.user?.role === 'teacher') {
    const isAuthorized = await DataIsolationHelper.isCourseAssignedToTeacher(idStr, req.user.id);
    if (!isAuthorized) {
      return log.fail('access_denied', res, 403, 'Bạn không có quyền truy cập khóa học này');
    }
  }

  const course = await courseService.getCourseById(idStr);
  log.success(res, course, 'Course retrieved successfully');
});
```

#### 1.2 Update Payment Controller

```typescript
// src/interface/controllers/payment.controller.ts

export const getAllPayments = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('payment.get_all', req);
  log.start({ query: req.query });

  const filters = { ...req.query };

  // === DATA ISOLATION ===
  if (req.user?.role === 'teacher') {
    const teacherId = req.user.id;
    const courseStudentFilter = await DataIsolationHelper.buildCourseStudentFilter(teacherId);

    // Merge filter: phải thỏa mãn cả course_student của teacher
    filters.course_student_id = courseStudentFilter.course_student_id;
  }
  // Admin/Staff: không filter

  const payments = await paymentService.getAllPayments(filters, req.pagination);
  log.success((res as any), payments, 'Payments retrieved successfully');
});

export const createPayment = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('payment.create', req);
  log.start({});

  // === DATA ISOLATION ===
  // Teacher chỉ được tạo payment cho học viên được gán
  if (req.user?.role === 'teacher') {
    const { course_student_id } = req.body;
    if (course_student_id) {
      const isAuthorized = await DataIsolationHelper.isCourseStudentOwnedByTeacher(
        course_student_id,
        req.user.id
      );
      if (!isAuthorized) {
        return log.fail('access_denied', res, 403, 'Bạn không có quyền tạo thanh toán cho học viên này');
      }
    }
  }

  const payment = await paymentService.createPayment(req.body);
  log.success((res as any), payment, 'Payment recorded successfully');
});

export const updatePayment = catchAsync(async (req: any, res: Response) => {
  const log = ctrlLogger('payment.update', req);
  const idStr = typeof req.params.id === 'string' ? req.params.id : req.params.id[0];
  log.start({ paymentId: idStr });

  // === DATA ISOLATION ===
  if (req.user?.role === 'teacher') {
    // Cần kiểm tra payment có thuộc course_student của teacher không
    const payment = await PaymentModel.findById(idStr);
    if (payment) {
      const isAuthorized = await DataIsolationHelper.isCourseStudentOwnedByTeacher(
        payment.course_student_id,
        req.user.id
      );
      if (!isAuthorized) {
        return log.fail('access_denied', res, 403, 'Bạn không có quyền cập nhật thanh toán này');
      }
    }
  }

  const payment = await paymentService.updatePayment(idStr, req.body);
  log.success((res as any), payment, 'Payment updated successfully');
});
